// Fluide néon — solveur « stable fluids » (Navier-Stokes) sur GPU, WebGL2 pur.
var canvas = document.getElementById("fluid");
var hint = document.getElementById("hint");
var gl = canvas.getContext("webgl2", { alpha: false, depth: false, stencil: false, antialias: false });
var extOK = gl && gl.getExtension("EXT_color_buffer_float");
gl && gl.getExtension("OES_texture_float_linear");

if (!gl || !extOK) {
  hint.innerHTML = "⚠️ Ce labo demande WebGL2 (EXT_color_buffer_float). Essaie un navigateur récent.";
} else {
  // --- Compilation des shaders -------------------------------------------
  function compile(type, src) {
    var s = gl.createShader(type);
    gl.shaderSource(s, src);
    gl.compileShader(s);
    if (!gl.getShaderParameter(s, gl.COMPILE_STATUS)) throw new Error(gl.getShaderInfoLog(s));
    return s;
  }
  var VERT = compile(gl.VERTEX_SHADER, [
    "precision highp float;",
    "attribute vec2 aPos;",
    "varying vec2 vUv, vL, vR, vT, vB;",
    "uniform vec2 texelSize;",
    "void main(){",
    "  vUv = aPos * 0.5 + 0.5;",
    "  vL = vUv - vec2(texelSize.x, 0.0); vR = vUv + vec2(texelSize.x, 0.0);",
    "  vT = vUv + vec2(0.0, texelSize.y); vB = vUv - vec2(0.0, texelSize.y);",
    "  gl_Position = vec4(aPos, 0.0, 1.0);",
    "}",
  ].join("\n"));

  function program(fragSrc) {
    var p = gl.createProgram();
    gl.attachShader(p, VERT);
    gl.attachShader(p, compile(gl.FRAGMENT_SHADER, "precision highp float;precision highp sampler2D;varying vec2 vUv,vL,vR,vT,vB;" + fragSrc));
    gl.linkProgram(p);
    if (!gl.getProgramParameter(p, gl.LINK_STATUS)) throw new Error(gl.getProgramInfoLog(p));
    var u = {}, n = gl.getProgramParameter(p, gl.ACTIVE_UNIFORMS);
    for (var i = 0; i < n; i++) { var info = gl.getActiveUniform(p, i); u[info.name] = gl.getUniformLocation(p, info.name); }
    return { p: p, u: u };
  }

  var splatProg = program(
    "uniform sampler2D uTarget;uniform float aspect;uniform vec2 point;uniform vec3 color;uniform float radius;" +
    "void main(){vec2 d=vUv-point;d.x*=aspect;vec3 base=texture2D(uTarget,vUv).xyz;" +
    "gl_FragColor=vec4(base+exp(-dot(d,d)/radius)*color,1.0);}");
  var advectProg = program(
    "uniform sampler2D uVelocity;uniform sampler2D uSource;uniform vec2 texelSize;uniform float dt;uniform float dissipation;" +
    "void main(){vec2 coord=vUv-dt*texture2D(uVelocity,vUv).xy*texelSize;" +
    "gl_FragColor=texture2D(uSource,coord)/(1.0+dissipation*dt);gl_FragColor.a=1.0;}");
  var divProg = program(
    "uniform sampler2D uVelocity;" +
    "void main(){float L=texture2D(uVelocity,vL).x;float R=texture2D(uVelocity,vR).x;" +
    "float T=texture2D(uVelocity,vT).y;float B=texture2D(uVelocity,vB).y;" +
    "gl_FragColor=vec4(0.5*(R-L+T-B),0.0,0.0,1.0);}");
  var curlProg = program(
    "uniform sampler2D uVelocity;" +
    "void main(){float L=texture2D(uVelocity,vL).y;float R=texture2D(uVelocity,vR).y;" +
    "float T=texture2D(uVelocity,vT).x;float B=texture2D(uVelocity,vB).x;" +
    "gl_FragColor=vec4(0.5*(R-L-T+B),0.0,0.0,1.0);}");
  var vortProg = program(
    "uniform sampler2D uVelocity;uniform sampler2D uCurl;uniform float curl;uniform float dt;" +
    "void main(){float L=texture2D(uCurl,vL).x;float R=texture2D(uCurl,vR).x;" +
    "float T=texture2D(uCurl,vT).x;float B=texture2D(uCurl,vB).x;float C=texture2D(uCurl,vUv).x;" +
    "vec2 force=0.5*vec2(abs(T)-abs(B),abs(R)-abs(L));force/=length(force)+0.0001;force*=curl*C;force.y*=-1.0;" +
    "vec2 vel=texture2D(uVelocity,vUv).xy;gl_FragColor=vec4(vel+force*dt,0.0,1.0);}");
  var pressProg = program(
    "uniform sampler2D uPressure;uniform sampler2D uDivergence;" +
    "void main(){float L=texture2D(uPressure,vL).x;float R=texture2D(uPressure,vR).x;" +
    "float T=texture2D(uPressure,vT).x;float B=texture2D(uPressure,vB).x;" +
    "float div=texture2D(uDivergence,vUv).x;gl_FragColor=vec4((L+R+B+T-div)*0.25,0.0,0.0,1.0);}");
  var gradProg = program(
    "uniform sampler2D uPressure;uniform sampler2D uVelocity;" +
    "void main(){float L=texture2D(uPressure,vL).x;float R=texture2D(uPressure,vR).x;" +
    "float T=texture2D(uPressure,vT).x;float B=texture2D(uPressure,vB).x;" +
    "vec2 vel=texture2D(uVelocity,vUv).xy-vec2(R-L,T-B);gl_FragColor=vec4(vel,0.0,1.0);}");
  var displayProg = program(
    "uniform sampler2D uTexture;" +
    "void main(){vec3 c=texture2D(uTexture,vUv).rgb;" +
    "c+=c*c*0.6;" + // rehausse façon bloom : les zones denses brillent
    "float d=distance(vUv,vec2(0.5));c*=1.0-0.35*d*d;" + // vignette douce
    "gl_FragColor=vec4(c,1.0);}");

  // --- Quad plein écran ----------------------------------------------------
  gl.bindBuffer(gl.ARRAY_BUFFER, gl.createBuffer());
  gl.bufferData(gl.ARRAY_BUFFER, new Float32Array([-1, -1, 1, -1, -1, 1, 1, 1]), gl.STATIC_DRAW);
  function blit(target) {
    gl.bindFramebuffer(gl.FRAMEBUFFER, target ? target.fbo : null);
    gl.viewport(0, 0, target ? target.w : gl.drawingBufferWidth, target ? target.h : gl.drawingBufferHeight);
    gl.drawArrays(gl.TRIANGLE_STRIP, 0, 4);
  }

  // --- FBOs (textures flottantes) ------------------------------------------
  function createFBO(w, h, internal, format) {
    var tex = gl.createTexture();
    gl.bindTexture(gl.TEXTURE_2D, tex);
    gl.texParameteri(gl.TEXTURE_2D, gl.TEXTURE_MIN_FILTER, gl.LINEAR);
    gl.texParameteri(gl.TEXTURE_2D, gl.TEXTURE_MAG_FILTER, gl.LINEAR);
    gl.texParameteri(gl.TEXTURE_2D, gl.TEXTURE_WRAP_S, gl.CLAMP_TO_EDGE);
    gl.texParameteri(gl.TEXTURE_2D, gl.TEXTURE_WRAP_T, gl.CLAMP_TO_EDGE);
    gl.texImage2D(gl.TEXTURE_2D, 0, internal, w, h, 0, format, gl.HALF_FLOAT, null);
    var fbo = gl.createFramebuffer();
    gl.bindFramebuffer(gl.FRAMEBUFFER, fbo);
    gl.framebufferTexture2D(gl.FRAMEBUFFER, gl.COLOR_ATTACHMENT0, gl.TEXTURE_2D, tex, 0);
    gl.clearColor(0, 0, 0, 1);
    gl.clear(gl.COLOR_BUFFER_BIT);
    return { tex: tex, fbo: fbo, w: w, h: h, attach: function (id) { gl.activeTexture(gl.TEXTURE0 + id); gl.bindTexture(gl.TEXTURE_2D, this.tex); return id; } };
  }
  function doubleFBO(w, h, internal, format) {
    var a = createFBO(w, h, internal, format), b = createFBO(w, h, internal, format);
    return { get read() { return a; }, get write() { return b; }, swap: function () { var t = a; a = b; b = t; }, w: w, h: h };
  }

  var SIM = 128, DYE = 512;
  var dye, velocity, divergence, curlFBO, pressure;
  function initFBOs() {
    var ar = canvas.width / Math.max(1, canvas.height);
    var sw = ar > 1 ? Math.round(SIM * ar) : SIM, sh = ar > 1 ? SIM : Math.round(SIM / ar);
    var dw = ar > 1 ? Math.round(DYE * ar) : DYE, dh = ar > 1 ? DYE : Math.round(DYE / ar);
    dye = doubleFBO(dw, dh, gl.RGBA16F, gl.RGBA);
    velocity = doubleFBO(sw, sh, gl.RG16F, gl.RG);
    divergence = createFBO(sw, sh, gl.R16F, gl.RED);
    curlFBO = createFBO(sw, sh, gl.R16F, gl.RED);
    pressure = doubleFBO(sw, sh, gl.R16F, gl.RED);
  }

  function resize() {
    var w = canvas.clientWidth, h = canvas.clientHeight;
    if (canvas.width !== w || canvas.height !== h) { canvas.width = w; canvas.height = h; initFBOs(); }
  }

  function bind(prog) {
    gl.useProgram(prog.p);
    var loc = gl.getAttribLocation(prog.p, "aPos");
    gl.enableVertexAttribArray(loc);
    gl.vertexAttribPointer(loc, 2, gl.FLOAT, false, 0, 0);
    return prog.u;
  }

  // --- Couleurs néon (HSV → RGB, teinte qui tourne) -------------------------
  var hue = Math.random();
  function neonColor() {
    hue = (hue + 0.13 + Math.random() * 0.08) % 1;
    var h = hue * 6, i = Math.floor(h), f = h - i;
    var r = [1, 1 - f, 0, 0, f, 1][i % 6], g = [f, 1, 1, 1 - f, 0, 0][i % 6], b = [0, 0, f, 1, 1, 1 - f][i % 6];
    return [r * 0.36, g * 0.36, b * 0.36];
  }

  function splat(x, y, dx, dy, color) {
    var aspect = canvas.width / Math.max(1, canvas.height);
    var u = bind(splatProg);
    gl.uniform2f(u.texelSize, 1 / velocity.w, 1 / velocity.h);
    gl.uniform1i(u.uTarget, velocity.read.attach(0));
    gl.uniform1f(u.aspect, aspect);
    gl.uniform2f(u.point, x, y);
    gl.uniform3f(u.color, dx, dy, 0);
    gl.uniform1f(u.radius, 0.0028);
    blit(velocity.write); velocity.swap();
    gl.uniform1i(u.uTarget, dye.read.attach(0));
    gl.uniform3f(u.color, color[0], color[1], color[2]);
    blit(dye.write); dye.swap();
  }

  function randomSplats(n) {
    for (var i = 0; i < n; i++) {
      splat(Math.random(), Math.random(), (Math.random() - 0.5) * 900, (Math.random() - 0.5) * 900, neonColor());
    }
  }

  // --- Boucle de simulation --------------------------------------------------
  var last = performance.now(), idleTimer = 0;
  function step(now) {
    var dt = Math.min((now - last) / 1000, 0.016);
    last = now;
    resize();

    var u = bind(curlProg);
    gl.uniform2f(u.texelSize, 1 / velocity.w, 1 / velocity.h);
    gl.uniform1i(u.uVelocity, velocity.read.attach(0));
    blit(curlFBO);

    u = bind(vortProg);
    gl.uniform2f(u.texelSize, 1 / velocity.w, 1 / velocity.h);
    gl.uniform1i(u.uVelocity, velocity.read.attach(0));
    gl.uniform1i(u.uCurl, curlFBO.attach(1));
    gl.uniform1f(u.curl, 34);
    gl.uniform1f(u.dt, dt);
    blit(velocity.write); velocity.swap();

    u = bind(divProg);
    gl.uniform2f(u.texelSize, 1 / velocity.w, 1 / velocity.h);
    gl.uniform1i(u.uVelocity, velocity.read.attach(0));
    blit(divergence);

    u = bind(pressProg);
    gl.uniform2f(u.texelSize, 1 / velocity.w, 1 / velocity.h);
    gl.uniform1i(u.uDivergence, divergence.attach(1));
    for (var i = 0; i < 22; i++) {
      gl.uniform1i(u.uPressure, pressure.read.attach(0));
      blit(pressure.write); pressure.swap();
    }

    u = bind(gradProg);
    gl.uniform2f(u.texelSize, 1 / velocity.w, 1 / velocity.h);
    gl.uniform1i(u.uPressure, pressure.read.attach(0));
    gl.uniform1i(u.uVelocity, velocity.read.attach(1));
    blit(velocity.write); velocity.swap();

    u = bind(advectProg);
    gl.uniform2f(u.texelSize, 1 / velocity.w, 1 / velocity.h);
    gl.uniform1i(u.uVelocity, velocity.read.attach(0));
    gl.uniform1i(u.uSource, velocity.read.attach(0));
    gl.uniform1f(u.dt, dt);
    gl.uniform1f(u.dissipation, 0.06);
    blit(velocity.write); velocity.swap();

    gl.uniform1i(u.uVelocity, velocity.read.attach(0));
    gl.uniform1i(u.uSource, dye.read.attach(1));
    gl.uniform1f(u.dissipation, 0.28);
    blit(dye.write); dye.swap();

    u = bind(displayProg);
    gl.uniform2f(u.texelSize, 1 / canvas.width, 1 / canvas.height);
    gl.uniform1i(u.uTexture, dye.read.attach(0));
    blit(null);

    // Respire tout seul si personne ne touche.
    idleTimer += dt;
    if (idleTimer > 2.6) { idleTimer = 0; randomSplats(1 + Math.floor(Math.random() * 2)); }

    requestAnimationFrame(step);
  }

  // --- Interactions (souris + multi-touch) -----------------------------------
  var pointers = {};
  function pos(e) {
    var r = canvas.getBoundingClientRect();
    return { x: (e.clientX - r.left) / r.width, y: 1 - (e.clientY - r.top) / r.height };
  }
  canvas.addEventListener("pointerdown", function (e) {
    var p = pos(e);
    pointers[e.pointerId] = { x: p.x, y: p.y, color: neonColor() };
    splat(p.x, p.y, 0, 0, pointers[e.pointerId].color);
  });
  canvas.addEventListener("pointermove", function (e) {
    var prev = pointers[e.pointerId];
    var p = pos(e);
    if (!prev) { // survol sans clic : traînée légère
      splat(p.x, p.y, e.movementX * 6, -e.movementY * 6, neonColor());
      return;
    }
    var dx = (p.x - prev.x) * 3200, dy = (p.y - prev.y) * 3200;
    splat(p.x, p.y, dx, dy, prev.color);
    prev.x = p.x; prev.y = p.y;
  });
  window.addEventListener("pointerup", function (e) { delete pointers[e.pointerId]; });
  canvas.addEventListener("touchmove", function (e) { e.preventDefault(); }, { passive: false });

  document.getElementById("burst").addEventListener("click", function () { randomSplats(8); });

  resize();
  initFBOs();
  randomSplats(6);
  requestAnimationFrame(step);
}

